{
  "activities": [
    {
      "type": "activity",
      "title": "Reading Comprehension Practice",
      "unit_name": "Reading Skills",
      "chapter_name": "Reading Skills",
      "details": "Students engage in reading discursive passages (400-450 words) and case-based factual passages with visual input (200-250 words) to practice comprehension, interpretation, analysis, inference, evaluation, and vocabulary skills."
    },
    {
      "type": "activity",
      "title": "Grammar Accuracy Drill",
      "unit_name": "Writing Skills and Grammar",
      "chapter_name": "Writing Skills and Grammar",
      "details": "Students practice Determiners, Tenses, Modals, Subject-verb concord, and Reported speech through Gap Filling, Editing, and Transformation exercises to ensure accurate use of spelling, punctuation, and grammar."
    },
    {
      "type": "activity",
      "title": "Descriptive Writing Workshop",
      "unit_name": "Writing Skills and Grammar",
      "chapter_name": "Writing Skills and Grammar",
      "details": "Students write descriptive paragraphs (100-120 words) based on visual or verbal cues describing a person, event, or situation."
    },
    {
      "type": "activity",
      "title": "Creative Storytelling Session",
      "unit_name": "Writing Skills and Grammar",
      "chapter_name": "Writing Skills and Grammar",
      "details": "Students compose a story on a given cue/title or a diary entry (100-120 words) to develop creative expression."
    },
    {
      "type": "activity",
      "title": "Literature Context Analysis",
      "unit_name": "Language through Literature",
      "chapter_name": "Reference to the Context",
      "details": "Students analyze extracts from Drama/Prose and Poetry to assess interpretation, analysis, inference, evaluation, appreciation, and vocabulary."
    },
    {
      "type": "activity",
      "title": "Short Answer Discussion",
      "unit_name": "Language through Literature",
      "chapter_name": "Short & Long Answer Questions",
      "details": "Students answer short answer type questions (40-50 words) from Beehive and Moments to assess interpretation, analysis, inference, and evaluation."
    },
    {
      "type": "activity",
      "title": "Long Answer Creative Writing",
      "unit_name": "Language through Literature",
      "chapter_name": "Short & Long Answer Questions",
      "details": "Students answer long answer type questions (100-120 words) from Beehive and Moments focusing on creativity, imagination, extrapolation beyond the text, theme interpretation, or character sketches."
    },
    {
      "type": "activity",
      "title": "Role Play and Skit Performance",
      "unit_name": "Beehive (Prose)",
      "chapter_name": "My Childhood",
      "details": "Students participate in role plays, skits, or dramatizations based on prose texts to encourage classroom interaction and expression of ideas."
    },
    {
      "type": "activity",
      "title": "Group Discussion Forum",
      "unit_name": "Language through Literature",
      "chapter_name": "Reference to the Context",
      "details": "Students engage in group discussions to express their views, defend their opinions, and participate actively in class."
    },
    {
      "type": "activity",
      "title": "Listening and Speaking Practice",
      "unit_name": "Internal Assessment",
      "chapter_name": "Listening and Speaking",
      "details": "Regular practice of listening and speaking skills through activities designed to assess communication competencies."
    }
  ],
  "projects": [
    {
      "title": "Art-Integrated Literature Project",
      "unit_name": "Internal Assessment",
      "chapter_name": "Listening and Speaking",
      "details": "Students create art-integrated projects based on activities like Role Play, Skit, or Dramatization of prescribed texts to demonstrate understanding and creativity."
    }
  ],
  "practicals": [
    {
      "title": "Listening and Speaking Assessment",
      "unit_name": "Internal Assessment",
      "chapter_name": "Listening and Speaking",
      "details": "Formal assessment of Listening and Speaking skills worth 05 marks, focusing on practical application of language skills as per CBSE guidelines."
    }
  ]
}
